import type { HTMLAttributes } from 'react';
import type { FileUploaderListItem } from './FileUploaderListItem/FileUploaderListItem.types';
export interface FileUploaderListProps extends HTMLAttributes<HTMLDivElement> {
    /** Перечень загруженных файлов
     * @param id: string - идентификатор
     * @param name: string - название
     * @param state: string - состояние файла, перечень состояний описан в IFileState
     * @param iconName: string - кастомная иконка
     */
    files?: FileUploaderListItem[];
    /** Обработчик события удаления файла */
    onRefresh?: (fileName: FileUploaderListItem) => void;
    /** Обработчик события повторной отправки файла */
    onRemove?: (fileName: FileUploaderListItem) => void;
}
